import{c as t,S as h,j as i,m as o}from"./chunks/framework.8aa1YH_s.js";const d=JSON.parse('{"title":"Đề ôn khóa học","description":"","frontmatter":{},"headers":[],"relativePath":"admin/de-on-khoa-hoc.md","filePath":"admin/de-on-khoa-hoc.md","lastUpdated":0}'),a={name:"admin/de-on-khoa-hoc.md"};function c(r,n,l,g,s,e){return h(),i("div",null,[...n[0]||(n[0]=[o('<h1 id="đe-on-khoa-hoc" tabindex="-1">Đề ôn khóa học <a class="header-anchor" href="#đe-on-khoa-hoc" aria-label="Permalink to “Đề ôn khóa học”">​</a></h1><p><strong>Đường dẫn:</strong> <code>https://lamsonedutech.vn/admin/question/exam</code></p><p>Đề ôn khóa học là <strong>đề luyện tập gắn với một khóa học cụ thể</strong>. Học viên đã mua khóa sẽ thấy các đề này trong tab &quot;Đề ôn&quot; của khóa và làm để củng cố kiến thức sau mỗi chương / chuyên đề.</p><h2 id="phan-biet-voi-cac-loai-đe-khac" tabindex="-1">Phân biệt với các loại đề khác <a class="header-anchor" href="#phan-biet-voi-cac-loai-đe-khac" aria-label="Permalink to “Phân biệt với các loại đề khác”">​</a></h2><table tabindex="0"><thead><tr><th>Loại đề</th><th>Mục đích</th><th>Module</th></tr></thead><tbody><tr><td><strong>Đề ôn khóa học</strong></td><td>Luyện tập theo khóa học, có thể làm nhiều lần</td><td>Trang này</td></tr><tr><td><strong>Đề kiểm tra cuối chuyên đề</strong></td><td>Tính điểm tiến độ trong <a href="./chuong-chuyen-de">Chuyên đề</a></td><td>Tạo từ chuyên đề</td></tr><tr><td><strong>Đề mẫu Luyện thi</strong> (HSA/TSA/THPT)</td><td>Giả lập kỳ thi thật, đếm ngược thời gian</td><td><a href="./de-mau-luyen-thi">Đề mẫu Luyện thi</a></td></tr><tr><td><strong>Đánh giá đầu vào</strong></td><td>Đo trình độ trước khi vào khóa</td><td><a href="./danh-gia-dau-vao">Đánh giá đầu vào</a></td></tr><tr><td><strong>Bộ đề thi</strong></td><td>Tập hợp nhiều đề để gán hàng loạt cho lớp</td><td><a href="./bo-de-thi">Bộ đề thi</a></td></tr></tbody></table><h2 id="danh-sach-đe-on" tabindex="-1">Danh sách đề ôn <a class="header-anchor" href="#danh-sach-đe-on" aria-label="Permalink to “Danh sách đề ôn”">​</a></h2><p>Cột chính:</p><table tabindex="0"><thead><tr><th>Cột</th><th>Ý nghĩa</th></tr></thead><tbody><tr><td>Tên đề</td><td>Tên đề ôn</td></tr><tr><td>Khóa học</td><td>Khóa được gắn vào</td></tr><tr><td>Chương / Chuyên đề</td><td>Chương / chuyên đề liên kết (nếu có)</td></tr><tr><td>Số câu</td><td>Tổng câu hỏi</td></tr><tr><td>Thời gian (phút)</td><td>Thời lượng làm bài</td></tr><tr><td>Tổng điểm</td><td>Mặc định 10</td></tr><tr><td>Chế độ</td><td>Cố định / Random theo tiêu chí</td></tr><tr><td>Lượt làm</td><td>Số lượt học viên đã làm</td></tr><tr><td>Trạng thái</td><td>Công khai / Nháp / Ẩn</td></tr></tbody></table><h3 id="bo-loc" tabindex="-1">Bộ lọc <a class="header-anchor" href="#bo-loc" aria-label="Permalink to “Bộ lọc”">​</a></h3><ul><li>Theo <strong>Khóa học</strong>.</li><li>Theo <strong>Chương / Chuyên đề</strong>.</li><li>Theo <strong>Trạng thái</strong>.</li><li>Theo <strong>Người tạo</strong>.</li><li>Tìm kiếm theo <strong>Tên đề</strong>.</li></ul><h2 id="tao-moi-đe-on" tabindex="-1">Tạo mới đề ôn <a class="header-anchor" href="#tao-moi-đe-on" aria-label="Permalink to “Tạo mới đề ôn”">​</a></h2><ol><li>Bấm <strong>Thêm mới</strong>.</li><li>Khai báo thông tin cơ bản: <ul><li><strong>Tên đề</strong> (vd &quot;Đề ôn Chương 2 - Hàm số bậc hai&quot;).</li><li><strong>Khóa học</strong>: chọn khóa sẽ gắn đề vào.</li><li><strong>Chương / Chuyên đề</strong> (tùy chọn): nếu chỉ áp dụng cho 1 chuyên đề cụ thể.</li><li><strong>Mô tả</strong> ngắn cho học viên.</li><li><strong>Thời gian làm bài</strong> (phút).</li><li><strong>Tổng điểm</strong> (mặc định 10).</li></ul></li><li>Chọn <strong>chế độ dựng đề</strong>: <ul><li><strong>Cố định</strong>: chọn tay từng câu hỏi.</li><li><strong>Theo tiêu chí</strong>: chọn 1 <a href="./tieu-chi-de-thi">Tiêu chí đề thi</a> → hệ thống random câu.</li></ul></li><li>Cấu hình <strong>luật làm bài</strong>: <ul><li><strong>Số lần làm lại tối đa</strong> (0 = không giới hạn).</li><li><strong>Hiển thị đáp án sau khi nộp</strong>: Có / Không / Chỉ hiển thị đúng-sai.</li><li><strong>Trộn câu hỏi</strong> giữa các lần làm.</li><li><strong>Trộn đáp án</strong> trong từng câu.</li><li><strong>Random lại đề</strong> mỗi lần làm (chỉ khi chế độ Theo tiêu chí).</li></ul></li><li>(Tùy chọn) <strong>Thời gian mở/đóng đề</strong>: chỉ học viên trong khoảng thời gian này mới được làm.</li><li>Bấm <strong>Lưu</strong>.</li></ol><div class="tip custom-block"><p class="custom-block-title custom-block-title-default">TIP</p><p>Để khóa <strong>Luyện đề thực chiến</strong>, hãy bật <strong>Đếm ngược thời gian</strong> và <strong>Không cho xem lại đáp án từng câu khi đang làm</strong> — giả lập tâm lý phòng thi.</p></div><h2 id="chon-cau-hoi-che-đo-co-đinh" tabindex="-1">Chọn câu hỏi (chế độ Cố định) <a class="header-anchor" href="#chon-cau-hoi-che-đo-co-đinh" aria-label="Permalink to “Chọn câu hỏi (chế độ Cố định)”">​</a></h2><ol><li>Sau khi lưu thông tin cơ bản, mở chi tiết đề.</li><li>Vào tab <strong>Câu hỏi</strong>.</li><li>Bấm <strong>Thêm câu hỏi</strong>.</li><li>Trong popup chọn câu: <ul><li>Lọc theo <strong>Môn</strong>, <strong>Chuyên đề</strong>, <strong>Mức độ</strong>, <strong>Dạng câu</strong>.</li><li>Tích chọn các câu cần thêm.</li><li>Bấm <strong>Thêm vào đề</strong>.</li></ul></li><li>Sau khi thêm, có thể: <ul><li><strong>Kéo-thả</strong> để sắp xếp thứ tự.</li><li><strong>Sửa điểm</strong> từng câu.</li><li><strong>Xóa</strong> câu khỏi đề.</li></ul></li><li>Kiểm tra <strong>Tổng số câu</strong> và <strong>Tổng điểm</strong> ở cuối trang.</li><li>Bấm <strong>Lưu</strong>.</li></ol><h2 id="dung-tieu-chi-che-đo-random" tabindex="-1">Dùng Tiêu chí (chế độ Random) <a class="header-anchor" href="#dung-tieu-chi-che-đo-random" aria-label="Permalink to “Dùng Tiêu chí (chế độ Random)”">​</a></h2><ol><li>Tạo trước <a href="./tieu-chi-de-thi">Tiêu chí đề thi</a> phù hợp.</li><li>Khi tạo đề ôn, chọn chế độ <strong>Theo tiêu chí</strong>.</li><li>Chọn tiêu chí từ dropdown.</li><li>(Tùy chọn) Bấm <strong>Xem thử đề</strong> để hệ thống dựng thử 1 đề mẫu — kiểm tra số câu và mức độ.</li><li>Lưu.</li></ol><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>Khi dùng Theo tiêu chí, <strong>mỗi học viên (mỗi lượt làm)</strong> sẽ nhận tập câu hỏi khác nhau. Điều này có lợi cho việc chống gian lận, nhưng làm cho việc <strong>giải đề / chữa đề</strong> khó hơn — vì mỗi em một đề khác.</p></div><h2 id="sua-đe-on" tabindex="-1">Sửa đề ôn <a class="header-anchor" href="#sua-đe-on" aria-label="Permalink to “Sửa đề ôn”">​</a></h2><ol><li>Tại danh sách, bấm <strong>Sửa</strong>.</li><li>Cập nhật thông tin / câu hỏi.</li><li>Bấm <strong>Lưu</strong>.</li></ol><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>Nếu đề đã có lượt làm, việc <strong>xóa/sửa câu</strong> sẽ ảnh hưởng tới điểm cũ của học viên (vì cấu trúc đề thay đổi). Khuyến nghị <strong>tạo đề mới</strong> và ẩn đề cũ thay vì sửa.</p></div><h2 id="xoa-đe-on" tabindex="-1">Xóa đề ôn <a class="header-anchor" href="#xoa-đe-on" aria-label="Permalink to “Xóa đề ôn”">​</a></h2><ol><li>Tại danh sách, bấm <strong>Xóa</strong>.</li><li>Xác nhận.</li></ol><div class="danger custom-block"><p class="custom-block-title custom-block-title-default">DANGER</p><p>Đề đã có lượt làm sẽ không xóa được hoàn toàn — hệ thống chỉ ẩn để giữ lịch sử điểm. Nếu cần xóa hẳn, liên hệ quản trị hệ thống.</p></div><h2 id="nhan-ban-đe" tabindex="-1">Nhân bản đề <a class="header-anchor" href="#nhan-ban-đe" aria-label="Permalink to “Nhân bản đề”">​</a></h2><p>Khi cần tạo đề tương tự cho khóa khác:</p><ol><li>Tại danh sách, bấm <strong>Nhân bản</strong> trên dòng đề gốc.</li><li>Hệ thống tạo bản sao với hậu tố &quot;(Bản sao)&quot;.</li><li>Sửa <strong>Khóa học liên kết</strong> và <strong>Tên đề</strong>.</li><li>Lưu.</li></ol><h2 id="cong-khai-an-luu-tru" tabindex="-1">Công khai / Ẩn / Lưu trữ <a class="header-anchor" href="#cong-khai-an-luu-tru" aria-label="Permalink to “Công khai / Ẩn / Lưu trữ”">​</a></h2><ul><li><strong>Nháp</strong>: chỉ admin/giáo viên thấy, học viên không thấy.</li><li><strong>Công khai</strong>: học viên trong khóa thấy và làm được.</li><li><strong>Ẩn</strong>: học viên không thấy đề mới, ai đã làm vẫn xem được lịch sử.</li></ul><p>→ Đổi trạng thái bằng nút <strong>Đổi trạng thái</strong> trên dòng hoặc trong trang chi tiết.</p><h2 id="xem-ket-qua-hoc-vien" tabindex="-1">Xem kết quả học viên <a class="header-anchor" href="#xem-ket-qua-hoc-vien" aria-label="Permalink to “Xem kết quả học viên”">​</a></h2><p>Sau khi học viên làm đề:</p><ol><li>Vào chi tiết đề ôn → tab <strong>Kết quả</strong>.</li><li>Bảng hiển thị: học viên, lần làm, điểm, thời gian, ngày làm.</li><li>Bấm vào một dòng → xem chi tiết bài làm (từng câu đúng/sai).</li><li>Có thể <strong>Xuất Excel</strong> danh sách kết quả.</li></ol><p>→ Thống kê tổng hợp (top câu sai nhiều, độ khó từng câu) có ở <a href="./thong-ke">Thống kê</a>.</p><h2 id="nhap-xuat" tabindex="-1">Nhập / Xuất <a class="header-anchor" href="#nhap-xuat" aria-label="Permalink to “Nhập / Xuất”">​</a></h2><ul><li><strong>Xuất Excel</strong> danh sách đề ôn: tải xuống danh sách đề kèm metadata (khóa, số câu, thời gian).</li><li><strong>Xuất đề thi (file Word/PDF)</strong>: tại chi tiết đề, bấm <strong>Xuất đề</strong> → tải file Word/PDF để in giấy.</li></ul><h2 id="cau-hoi-thuong-gap" tabindex="-1">Câu hỏi thường gặp <a class="header-anchor" href="#cau-hoi-thuong-gap" aria-label="Permalink to “Câu hỏi thường gặp”">​</a></h2><p><strong>Tôi muốn đề ôn cho cả khóa, không gắn vào chuyên đề cụ thể.</strong> → Khi tạo đề, để trống ô <strong>Chuyên đề</strong> và chỉ chọn <strong>Khóa học</strong>. Đề sẽ xuất hiện ở tab &quot;Đề ôn chung&quot; của khóa.</p><p><strong>Học viên hoàn thành khóa nhưng đề ôn vẫn cho làm - có giới hạn được không?</strong> → Đặt <strong>Thời gian mở/đóng đề</strong> khi tạo. Sau ngày đóng, đề tự ẩn khỏi học viên.</p><p><strong>Đề ôn có tính vào tiến độ khóa học không?</strong> → <strong>Không</strong> mặc định. Tiến độ khóa tính theo bài giảng đã xem và đề kiểm tra cuối chuyên đề. Đề ôn chỉ để luyện tập.</p><p><strong>Tôi đã tạo đề theo tiêu chí, nhưng học viên thấy đề thiếu câu - vì sao?</strong> → Do <a href="./danh-muc-cau-hoi">Danh mục câu hỏi</a> không đủ câu thỏa tiêu chí. Mở tiêu chí → kiểm tra số câu khả dụng → bổ sung câu hỏi.</p><p><strong>Tôi muốn 1 đề dùng chung cho nhiều khóa khác nhau?</strong> → Mỗi đề ôn chỉ thuộc về 1 khóa. Nếu muốn dùng chung, hãy <strong>nhân bản</strong> đề cho từng khóa, hoặc dùng <a href="./bo-de-thi">Bộ đề thi</a> để gán hàng loạt.</p><p><strong>Học viên báo &quot;đề bị lock thời gian, không bấm nộp được&quot;.</strong> → Kiểm tra <strong>Thời gian làm bài</strong> đã chính xác chưa, và đảm bảo học viên có nộp trước khi hết giờ. Nếu hệ thống đã tự nộp khi hết giờ, vào tab Kết quả xem có ghi nhận điểm chưa.</p>',43)])])}const m=t(a,[["render",c]]);export{d as __pageData,m as default};
